+impl TaskSessionRepo for SqliteDb {
+    fn start_session(&self, task_id: &str, start_ts: &str) -> Result<(), RepoError> {
+        self.with_conn(|conn| {
+            conn.execute(
+                "INSERT INTO task_sessions (task_id, start_ts) VALUES (?1, ?2)",
+                rusqlite::params![task_id, start_ts],
+            )?;
+            Ok(())
+        })
